const r="usd_try_rate";async function a(){if(typeof localStorage<"u"){const t=localStorage.getItem(r);if(t){const{rate:n,timestamp:e}=JSON.parse(t);if(Date.now()-e<36e5)return n}}try{const t=await fetch("https://cdn.jsdelivr.net/npm/@fawazahmed0/currency-api@latest/v1/currencies/usd.json");if(!t.ok)throw new Error("API response not ok");const e=(await t.json()).usd?.try||35;return typeof localStorage<"u"&&localStorage.setItem(r,JSON.stringify({rate:e,timestamp:Date.now()})),e}catch(t){return console.warn("Failed to fetch exchange rate, using fallback:",t),35}}function o(t,n){const e=t*n;return new Intl.NumberFormat("tr-TR",{style:"currency",currency:"TRY",minimumFractionDigits:0,maximumFractionDigits:0}).format(e)}export{o as f,a as g};
